import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { v4 as uuidv4 } from 'uuid';
import { AppliancesService } from '../../services/appliances.service';

@Component({
  selector: 'app-appliances-edit',
  templateUrl: './appliances-edit.component.html'
})
export class AppliancesEditComponent implements OnInit {
  form: FormGroup;
  editingId?: string;

  constructor(private fb: FormBuilder, private route: ActivatedRoute, private router: Router, private svc: AppliancesService) {
    this.form = this.fb.group({
      name: ['', Validators.required],
      brand: [''],
      model: [''],
      location: [''],
      notes: ['']
    });
  }

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    if (id) {
      this.editingId = id;
      this.svc.list$.subscribe(list => {
        const item = list.find(i => i.id === id);
        if (item) this.form.patchValue(item as any);
      });
    }
  }

  save() {
    if (this.form.invalid) return;
    const payload = this.form.value;
    if (this.editingId) {
      this.svc.update(this.editingId, payload);
    } else {
      this.svc.add({ id: uuidv4(), ...payload, createdAt: new Date().toISOString() } as any);
    }
    this.router.navigate(['/appliances']);
  }
}
<div class="card">
  <h2 *ngIf="editingId; else newTitle">Edit Appliance</h2>
  <ng-template #newTitle><h2>New Appliance</h2></ng-template>

  <form [formGroup]="form" (ngSubmit)="save()">
    <div class="form-row">
      <input class="input" placeholder="Name" formControlName="name" />
      <input class="input" placeholder="Brand" formControlName="brand" />
    </div>
    <div class="form-row" style="margin-top:8px">
      <input class="input" placeholder="Model" formControlName="model" />
      <input class="input" placeholder="Location" formControlName="location" />
    </div>
    <div style="margin-top:8px">
      <textarea class="input" rows="4" placeholder="Notes" formControlName="notes"></textarea>
    </div>

    <div style="margin-top:12px">
      <button class="btn" type="submit">Save</button>
      <a routerLink="/appliances" style="margin-left:8px">Cancel</a>
    </div>
  </form>
</div>
